import React, { useEffect, useState } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from 'recharts';
import { fetchTopCreators } from '../services/api';

export default function TopCreatorsChart() {
  const [data, setData] = useState([]);

  useEffect(() => {
    fetchTopCreators()
      .then((res) => setData(res.data))
      .catch(console.error);
  }, []);

  if (data.length === 0) {
    return (
      <div className="card">
        <div className="card-header"><h2>Top Creators</h2></div>
        <div className="empty-state">No data yet</div>
      </div>
    );
  }

  return (
    <div className="card">
      <div className="card-header">
        <h2>Top Performing Creators</h2>
      </div>
      <ResponsiveContainer width="100%" height={300}>
        <BarChart data={data} layout="vertical" margin={{ left: 80 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#eee" />
          <XAxis type="number" tick={{ fontSize: 12 }} />
          <YAxis
            type="category"
            dataKey="creator"
            tick={{ fontSize: 12 }}
            width={80}
          />
          <Tooltip />
          <Bar dataKey="views" fill="#e94560" radius={[0, 4, 4, 0]} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}
